class adminDeveloperRepository {
  static async getDevelopers(page, filters) {
    const url = `https://properties.vzite.com/api/v1/developers?page=${page}&source=${filters.source}&name=${filters.name}`;
    const authToken = `Bearer ${Cookies.get("props_token")}`;
    var response = await axios.get(url, {
      headers: {
        Authorization: authToken
      }
    });
    let obj = { success: response.data.success };
    if (response.data.success) {
      obj.data = response.data.payload;
    } else {
      console.log(response.data.message);
    }
    return obj;
  }
  static async updateDeveloperStatus(referenceId) {
    const url = `https://properties.vzite.com/api/v1/developers/${referenceId}/update_status`;
    const authToken = `Bearer ${Cookies.get("props_token")}`;
    var response = await axios.get(url, {
      headers: {
        Authorization: authToken
      }
    });
    let obj = { success: response.data.success, message: response.data.message };
    if (response.data.success) {
      obj.data = response.data.payload;
    } else {
      console.log(response.data.message);
    }
    return obj;
  }
}
