class companyAgentRoleRepository {
  static async getRoleList(page = 1) {
    const url = `https://api.vzite.com/api/v1/company/agent_role?page=${page}`;
    var response = await axios.get(url);
    let obj = { success: response.data.success, message: response.data.message };
    if (response.data.success) {
      obj.data = response.data.payload;
    } else {
      console.log(response.data.message);
    }
    return obj;
  }
  static async saveRole(data) {
    const url = `https://api.vzite.com/api/v1/company/agent_role`;
    var response = await axios.post(url, data);
    let obj = { success: response.data.success, message: response.data.message };
    if (response.data.success) {
      obj.data = response.data.payload;
    } else {
      console.log(response.data.message);
    }
    return obj;
  }
  static async deleteRole(id) {
    const url = `https://api.vzite.com/api/v1/company/agent_role/${id}`;
    var response = await axios.delete(url);
    let obj = { success: response.data.success };
    if (response.data.success) {
      obj.data = response.data.payload;
    } else {
      console.log(response.data.message);
    }
    return obj;
  }
}
