class companyAuthRepository {
  static async companyLoginBySupertoken(data) {
    const url = `https://api.vzite.com/api/v1/company/loginBySuperToken?supertoken=${data.token}&email=${data.email}`;
    var response = await axios.get(url);
    let obj = { success: response.data.success };
    if (response.data.success) {
      obj.data = response.data.payload;
    } else {
      console.log(response.data.message);
    }
    return obj;
  }
  static async companyLogin(data) {
    const url = `https://api.vzite.com/api/v1/company/login`;
    var response = await axios.post(url, { email: data.email, password: data.password });
    let obj = { success: response.data.success, data: response.data.payload, message: response.data.message };
    return obj;
  }
  static async companyDetails() {
    const url = `https://api.vzite.com/api/v1/company`;
    var response = await axios.get(url);
    let obj = { success: response.data.success };
    if (response.data.success) {
      obj.data = response.data.payload;
    } else {
      console.log(response.data.message);
    }
    return obj;
  }
}
